INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'joo', 4, 1, NULL, 'John Brown of Haddington em Jo 4:1', 'Segundo John Brown of Haddington, a piedade prática e a santificação do coração ilumina o sentido deste texto. João 4 mostra que a pessoa e a obra redentora de Cristo sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'joo', 5, 1, NULL, 'Albert Barnes em Jo 5:1', 'Na leitura de Albert Barnes, vemos a exposição textual com aplicação pastoral objetiva. João 5 evidencia a pessoa e a obra redentora de Cristo como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Albert Barnes', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'joo', 6, 1, NULL, 'Martinho Lutero em Jo 6:1', 'Martinho Lutero interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em João 6, Deus revela a pessoa e a obra redentora de Cristo de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Martinho Lutero', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'joo', 7, 1, NULL, 'Thomas Boston em Jo 7:1', 'Thomas Boston destaca a piedade prática e a santificação do coração. Em João 7, o foco recai sobre a pessoa e a obra redentora de Cristo e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Thomas Boston', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'joo', 8, 1, NULL, 'Herman Bavinck em Jo 8:1', 'Herman Bavinck interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em João 8, Deus revela a pessoa e a obra redentora de Cristo de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Herman Bavinck', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'joo', 9, 1, NULL, 'Bernardo de Claraval em Jo 9:1', 'Segundo Bernardo de Claraval, a síntese entre fé, razão e vida santa ilumina o sentido deste texto. João 9 mostra que a pessoa e a obra redentora de Cristo sustenta a caminhada da fé, especialmente em arrependimento sincero. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Bernardo de Claraval', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'joo', 10, 1, NULL, 'William Gurnall em Jo 10:1', 'Na leitura de William Gurnall, vemos a piedade prática e a santificação do coração. João 10 evidencia a pessoa e a obra redentora de Cristo como eixo da vida do povo de Deus, com ênfase em esperança escatológica. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'William Gurnall', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'joo', 11, 1, NULL, 'Louis Berkhof em Jo 11:1', 'Segundo Louis Berkhof, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. João 11 mostra que a pessoa e a obra redentora de Cristo sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Louis Berkhof', 'commentary', '#1D4ED8', NOW()),
